    /// Returns a Path containing only the closed subpaths (filled in filled mode).
    public var closedPath: Path {
        switch self {
        case .ampersandSquare:
            return LucideLabIcon_Lab_AmpersandSquare.closedPath
        case .appleCore:
            return LucideLabIcon_Lab_AppleCore.closedPath
        case .arrowsUpDownSquare:
            return LucideLabIcon_Lab_ArrowsUpDownSquare.closedPath
